contracts/AgentRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./Interfaces.sol";

/**
 * @title AgentRegistry
 * @notice ERC-721-based on-chain identity registry for AI trading agents.
 *         Each agent is minted as an NFT token, stores its metadata, and carries
 *         a trust score that evolves with trade outcomes.
 *         Implements EIP-1271 for contract-wallet signature validation.
 *         Inspired by ERC-8004 agent identity standard.
 */
contract AgentRegistry is IERC721Metadata {

    bytes4 internal constant ERC1271_MAGIC_VALUE = 0x1626ba7e;

    // ── Events ────────────────────────────────────────────────────────────────
    event AgentRegistered(
        uint256 indexed agentId,
        address indexed owner,
        string name,
        string strategy
    );
    event AgentDeactivated(uint256 indexed agentId);
    event TrustScoreUpdated(uint256 indexed agentId, uint256 newScore);

    // ── Structs ───────────────────────────────────────────────────────────────
    struct Agent {
        uint256 id;
        address owner;
        string  name;
        string  strategy;
        string  endpoint;
        string  tokenURI;
        uint256 trustScore;
        uint256 totalTrades;
        uint256 profitableTrades;
        int256  totalPnlBps;
        bool    active;
        uint256 registeredAt;
    }

    // ── ERC-721 State ─────────────────────────────────────────────────────────
    string private _nftName;
    string private _nftSymbol;
    mapping(uint256 => address) private _owners;
    mapping(address => uint256) private _balances;
    mapping(uint256 => address) private _tokenApprovals;
    mapping(address => mapping(address => bool)) private _operatorApprovals;

    // ── Registry State ────────────────────────────────────────────────────────
    uint256 private _nextId = 1;
    mapping(uint256 => Agent)   private _agents;
    mapping(address => uint256[]) private _ownerAgents;

    address public reputationManager;
    address public owner;
    address public erc8004Registry;

    modifier onlyOwner() {
        require(msg.sender == owner, "AgentRegistry: not owner");
        _;
    }

    modifier onlyReputationManager() {
        require(
            msg.sender == reputationManager || msg.sender == owner,
            "AgentRegistry: not reputation manager"
        );
        _;
    }

    constructor() {
        owner             = msg.sender;
        reputationManager = msg.sender;
        _nftName          = "AITradingAgent";
        _nftSymbol        = "AITA";
    }

    // ── ERC-165 ───────────────────────────────────────────────────────────────

    function supportsInterface(bytes4 interfaceId)
        public pure override returns (bool)
    {
        return
            interfaceId == type(IERC721).interfaceId         ||
            interfaceId == type(IERC721Metadata).interfaceId ||
            interfaceId == type(IERC165).interfaceId;
    }

    // ── ERC-721 Metadata ──────────────────────────────────────────────────────

    function name()   external view override returns (string memory) { return _nftName; }
    function symbol() external view override returns (string memory) { return _nftSymbol; }

    function tokenURI(uint256 tokenId) external view override returns (string memory) {
        require(_owners[tokenId] != address(0), "AgentRegistry: nonexistent token");
        return _agents[tokenId].tokenURI;
    }

    // ── ERC-721 Core ──────────────────────────────────────────────────────────

    function balanceOf(address _owner) external view override returns (uint256) {
        require(_owner != address(0), "AgentRegistry: zero address");
        return _balances[_owner];
    }

    function ownerOf(uint256 tokenId) external view override returns (address) {
        address tokenOwner = _owners[tokenId];
        require(tokenOwner != address(0), "AgentRegistry: nonexistent token");
        return tokenOwner;
    }

    function approve(address to, uint256 tokenId) external override {
        address tokenOwner = _owners[tokenId];
        require(to != tokenOwner, "AgentRegistry: approve to current owner");
        require(
            msg.sender == tokenOwner || _operatorApprovals[tokenOwner][msg.sender],
            "AgentRegistry: not authorized"
        );
        _tokenApprovals[tokenId] = to;
        emit Approval(tokenOwner, to, tokenId);
    }

    function getApproved(uint256 tokenId) external view override returns (address) {
        require(_owners[tokenId] != address(0), "AgentRegistry: nonexistent token");
        return _tokenApprovals[tokenId];
    }

    function setApprovalForAll(address operator, bool approved) external override {
        require(operator != msg.sender, "AgentRegistry: approve to caller");
        _operatorApprovals[msg.sender][operator] = approved;
        emit ApprovalForAll(msg.sender, operator, approved);
    }

    function isApprovedForAll(address _owner, address operator)
        external view override returns (bool)
    {
        return _operatorApprovals[_owner][operator];
    }

    function transferFrom(address from, address to, uint256 tokenId) external override {
        require(_isApprovedOrOwner(msg.sender, tokenId), "AgentRegistry: not authorized");
        _transfer(from, to, tokenId);
    }

    function safeTransferFrom(address from, address to, uint256 tokenId) external override {
        require(_isApprovedOrOwner(msg.sender, tokenId), "AgentRegistry: not authorized");
        _transfer(from, to, tokenId);
        require(
            _checkOnERC721Received(from, to, tokenId, ""),
            "AgentRegistry: not ERC721Receiver"
        );
    }

    function safeTransferFrom(
        address from,
        address to,
        uint256 tokenId,
        bytes calldata data
    ) public override {
        require(_isApprovedOrOwner(msg.sender, tokenId), "AgentRegistry: not authorized");
        _transfer(from, to, tokenId);
        bytes memory dataCopy = data;
        require(
            _checkOnERC721Received(from, to, tokenId, dataCopy),
            "AgentRegistry: not ERC721Receiver"
        );
    }

    // ── EIP-1271 ──────────────────────────────────────────────────────────────

    function isValidSignature(bytes32 hash, bytes memory signature)
        external view returns (bytes4)
    {
        if (signature.length == 65) {
            bytes32 r; bytes32 s; uint8 v;
            assembly {
                r := mload(add(signature, 32))
                s := mload(add(signature, 64))
                v := byte(0, mload(add(signature, 96)))
            }
            address recovered = ecrecover(hash, v, r, s);
            if (recovered != address(0) && recovered == owner)
                return ERC1271_MAGIC_VALUE;
        }
        return 0xffffffff;
    }

    function isValidAgentSignature(
        uint256 agentId,
        bytes32 hash,
        bytes memory signature
    ) external view returns (bool) {
        address agentOwner = _agents[agentId].owner;
        require(agentOwner != address(0), "AgentRegistry: agent not found");

        if (signature.length == 65) {
            bytes32 r; bytes32 s; uint8 v;
            assembly {
                r := mload(add(signature, 32))
                s := mload(add(signature, 64))
                v := byte(0, mload(add(signature, 96)))
            }
            if (ecrecover(hash, v, r, s) == agentOwner) return true;
        }

        if (agentOwner.code.length > 0) {
            try IERC1271(agentOwner).isValidSignature(hash, signature)
                returns (bytes4 result)
            {
                return result == ERC1271_MAGIC_VALUE;
            } catch {
                return false;
            }
        }
        return false;
    }

    // ── External functions ────────────────────────────────────────────────────

    function registerAgent(
        string calldata name_,
        string calldata strategy,
        string calldata endpoint,
        string calldata tokenURI_
    ) external returns (uint256 agentId) {
        require(bytes(name_).length    > 0, "AgentRegistry: name required");
        require(bytes(strategy).length > 0, "AgentRegistry: strategy required");

        agentId = _nextId++;

        _agents[agentId] = Agent({
            id:               agentId,
            owner:            msg.sender,
            name:             name_,
            strategy:         strategy,
            endpoint:         endpoint,
            tokenURI:         tokenURI_,
            trustScore:       50,
            totalTrades:      0,
            profitableTrades: 0,
            totalPnlBps:      0,
            active:           true,
            registeredAt:     block.timestamp
        });

        _ownerAgents[msg.sender].push(agentId);
        _safeMint(msg.sender, agentId);

        emit AgentRegistered(agentId, msg.sender, name_, strategy);
    }

    function deactivateAgent(uint256 agentId) external {
        Agent storage agent = _agents[agentId];
        require(agent.owner == msg.sender, "AgentRegistry: not agent owner");
        require(agent.active,              "AgentRegistry: already inactive");
        agent.active = false;
        emit AgentDeactivated(agentId);
    }

    function updateReputation(
        uint256 agentId,
        bool    profitable,
        int256  pnlBps
    ) external onlyReputationManager {
        Agent storage agent = _agents[agentId];
        require(agent.active, "AgentRegistry: agent not active");

        agent.totalTrades++;
        agent.totalPnlBps += pnlBps;

        if (profitable) {
            agent.profitableTrades++;
            agent.trustScore = agent.trustScore >= 98 ? 100 : agent.trustScore + 2;
        } else {
            agent.trustScore = agent.trustScore <= 2  ? 0   : agent.trustScore - 2;
        }

        emit TrustScoreUpdated(agentId, agent.trustScore);
    }

    // ── View functions ────────────────────────────────────────────────────────

    function getAgent(uint256 agentId)
        external view
        returns (
            string memory agentName,
            string memory strategy,
            address agentOwner,
            uint256 trustScore,
            bool    active,
            uint256 totalTrades,
            uint256 profitableTrades
        )
    {
        Agent storage a = _agents[agentId];
        return (a.name, a.strategy, a.owner, a.trustScore, a.active, a.totalTrades, a.profitableTrades);
    }

    function getTrustScore(uint256 agentId) external view returns (uint256) {
        return _agents[agentId].trustScore;
    }

    function getAgentsByOwner(address agentOwner)
        external view returns (uint256[] memory)
    {
        return _ownerAgents[agentOwner];
    }

    function totalAgents() external view returns (uint256) {
        return _nextId - 1;
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setReputationManager(address manager) external onlyOwner {
        reputationManager = manager;
    }

    function setERC8004Registry(address registry) external onlyOwner {
        erc8004Registry = registry;
    }

    // ── Internal ERC-721 helpers ──────────────────────────────────────────────

    function _safeMint(address to, uint256 tokenId) internal {
        require(to != address(0),               "AgentRegistry: mint to zero");
        require(_owners[tokenId] == address(0), "AgentRegistry: already minted");
        _balances[to]   += 1;
        _owners[tokenId] = to;
        emit Transfer(address(0), to, tokenId);
        require(
            _checkOnERC721Received(address(0), to, tokenId, ""),
            "AgentRegistry: not ERC721Receiver"
        );
    }

    function _transfer(address from, address to, uint256 tokenId) internal {
        require(_owners[tokenId] == from, "AgentRegistry: wrong owner");
        require(to != address(0),         "AgentRegistry: transfer to zero");
        delete _tokenApprovals[tokenId];
        _balances[from]        -= 1;
        _balances[to]          += 1;
        _owners[tokenId]        = to;
        _agents[tokenId].owner  = to;
        _ownerAgents[to].push(tokenId);
        emit Transfer(from, to, tokenId);
    }

    function _isApprovedOrOwner(address spender, uint256 tokenId)
        internal view returns (bool)
    {
        address tokenOwner = _owners[tokenId];
        return (
            spender == tokenOwner                    ||
            _tokenApprovals[tokenId] == spender      ||
            _operatorApprovals[tokenOwner][spender]
        );
    }

    function _checkOnERC721Received(
        address from, address to, uint256 tokenId, bytes memory data
    ) internal returns (bool) {
        if (to.code.length == 0) return true;
        try IERC721Receiver(to).onERC721Received(msg.sender, from, tokenId, data)
            returns (bytes4 retval)
        {
            return retval == IERC721Receiver.onERC721Received.selector;
        } catch {
            return false;
        }
    }
}

contracts/Interfaces.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

// ── EIP-1271: Standard Signature Validation for Contract Wallets ──────────────
interface IERC1271 {
    function isValidSignature(bytes32 hash, bytes memory signature)
        external view returns (bytes4);
}

// ── ERC-721 Receiver ──────────────────────────────────────────────────────────
interface IERC721Receiver {
    function onERC721Received(
        address operator,
        address from,
        uint256 tokenId,
        bytes calldata data
    ) external returns (bytes4);
}

// ── ERC-165 ───────────────────────────────────────────────────────────────────
interface IERC165 {
    function supportsInterface(bytes4 interfaceId) external view returns (bool);
}

// ── ERC-721 ───────────────────────────────────────────────────────────────────
interface IERC721 is IERC165 {
    event Transfer(address indexed from, address indexed to, uint256 indexed tokenId);
    event Approval(address indexed owner, address indexed approved, uint256 indexed tokenId);
    event ApprovalForAll(address indexed owner, address indexed operator, bool approved);

    function balanceOf(address owner) external view returns (uint256);
    function ownerOf(uint256 tokenId) external view returns (address);
    function safeTransferFrom(address from, address to, uint256 tokenId, bytes calldata data) external;
    function safeTransferFrom(address from, address to, uint256 tokenId) external;
    function transferFrom(address from, address to, uint256 tokenId) external;
    function approve(address to, uint256 tokenId) external;
    function setApprovalForAll(address operator, bool approved) external;
    function getApproved(uint256 tokenId) external view returns (address);
    function isApprovedForAll(address owner, address operator) external view returns (bool);
}

// ── ERC-721 Metadata ──────────────────────────────────────────────────────────
interface IERC721Metadata is IERC721 {
    function name() external view returns (string memory);
    function symbol() external view returns (string memory);
    function tokenURI(uint256 tokenId) external view returns (string memory);
}

// ── Minimal Uniswap-V2-style DEX Router ──────────────────────────────────────
interface IDEXRouter {
    function swapExactTokensForTokens(
        uint256 amountIn,
        uint256 amountOutMin,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external returns (uint256[] memory amounts);

    function swapTokensForExactTokens(
        uint256 amountOut,
        uint256 amountInMax,
        address[] calldata path,
        address to,
        uint256 deadline
    ) external returns (uint256[] memory amounts);

    function getAmountsOut(uint256 amountIn, address[] calldata path)
        external view returns (uint256[] memory amounts);
}

contracts/ReputationManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./AgentRegistry.sol";
import "./ValidationRegistry.sol";

/**
 * @title ReputationManager
 * @notice Orchestrates trust score updates combining:
 *           - Trade PnL outcome
 *           - Confidence accuracy
 *           - Drawdown tracking (max drawdown for leaderboard)
 *           - Sharpe-proxy signals (win-rate + running PnL variance)
 *
 *         Caller access is open via onlyAuthorized so that RiskRouter and
 *         backend wallets can trigger updates automatically post-trade,
 *         removing the old onlyOwner bottleneck.
 */
contract ReputationManager {

    // ── Events ────────────────────────────────────────────────────────────────
    event ReputationUpdated(
        uint256 indexed agentId,
        uint256 newTrustScore,
        int256  scoreDelta,
        string  reason
    );
    event AuthorizedCallerSet(address indexed caller, bool authorized);
    event DrawdownUpdated(uint256 indexed agentId, uint256 maxDrawdownBps);

    // ── Structs ───────────────────────────────────────────────────────────────
    struct ScoreUpdate {
        uint256 agentId;
        string  tradeId;
        bool    profitable;
        int256  pnlBps;
        uint256 confidence;
        uint256 timestamp;
    }

    /**
     * @notice Per-agent performance metrics for leaderboard + Sharpe proxy.
     *
     *   Sharpe proxy  = avgPnlBps / stdDevProxy
     *   stdDevProxy   = sqrt(sumSquaredPnlBps/n - avg²)  (computed off-chain)
     *   maxDrawdownBps = peak-to-trough loss in absolute basis points
     */
    struct AgentStats {
        int256  peakPnlBps;
        int256  currentPnlBps;
        uint256 maxDrawdownBps;
        int256  sumPnlBps;
        uint256 sumSquaredPnlBps;
        uint256 tradeCount;
        uint256 winCount;
        uint256 lossCount;
        uint256 lastUpdated;
    }

    // ── State ─────────────────────────────────────────────────────────────────
    AgentRegistry      public agentRegistry;
    ValidationRegistry public validationRegistry;
    address public owner;

    mapping(address => bool)          public authorizedCallers;
    mapping(uint256 => ScoreUpdate[]) public agentHistory;
    mapping(uint256 => AgentStats)    public agentStats;

    int256 public constant MAX_POSITIVE_DELTA = 5;
    int256 public constant MAX_NEGATIVE_DELTA = -3;

    modifier onlyOwner() {
        require(msg.sender == owner, "ReputationManager: not owner");
        _;
    }

    /**
     * @notice Replaces the old onlyOwner on updateReputation.
     *         Allows owner, RiskRouter, or any whitelisted backend wallet to
     *         trigger updates automatically without manual intervention.
     */
    modifier onlyAuthorized() {
        require(
            msg.sender == owner || authorizedCallers[msg.sender],
            "ReputationManager: not authorized"
        );
        _;
    }

    constructor(address _registry, address _validationRegistry) {
        owner              = msg.sender;
        agentRegistry      = AgentRegistry(_registry);
        validationRegistry = ValidationRegistry(_validationRegistry);
        authorizedCallers[msg.sender] = true;
    }

    // ── Core ──────────────────────────────────────────────────────────────────

    /**
     * @notice Update an agent's reputation after a trade settles.
     *         Can be called by owner, RiskRouter, or any authorized caller.
     *
     * @param agentId    On-chain agent ID (ERC-721 token ID).
     * @param tradeId    Off-chain trade UUID (must exist in ValidationRegistry).
     * @param profitable Whether the trade was profitable.
     * @param pnlBps     PnL in basis points.
     */
    function updateReputation(
        uint256 agentId,
        string calldata tradeId,
        bool profitable,
        int256 pnlBps
    ) external onlyAuthorized {
        (,, uint256 confidence,,,,, ) =
            validationRegistry.getValidation(tradeId);

        int256 delta = _computeDelta(profitable, pnlBps, confidence);

        validationRegistry.recordOutcome(tradeId, profitable, pnlBps);
        agentRegistry.updateReputation(agentId, profitable, pnlBps);
        _updateAgentStats(agentId, profitable, pnlBps);

        agentHistory[agentId].push(ScoreUpdate({
            agentId:    agentId,
            tradeId:    tradeId,
            profitable: profitable,
            pnlBps:     pnlBps,
            confidence: confidence,
            timestamp:  block.timestamp
        }));

        uint256 newScore = agentRegistry.getTrustScore(agentId);
        emit ReputationUpdated(
            agentId, newScore, delta,
            profitable
                ? "Profitable trade - trust increased"
                : "Unprofitable trade - trust decreased"
        );
    }

    /**
     * @notice Direct update without a ValidationRegistry lookup.
     *         Used by RiskRouter in automated post-trade flows.
     */
    function updateReputationDirect(
        uint256 agentId,
        bool    profitable,
        int256  pnlBps,
        uint256 confidence
    ) external onlyAuthorized {
        int256 delta = _computeDelta(profitable, pnlBps, confidence);

        agentRegistry.updateReputation(agentId, profitable, pnlBps);
        _updateAgentStats(agentId, profitable, pnlBps);

        agentHistory[agentId].push(ScoreUpdate({
            agentId:    agentId,
            tradeId:    "",
            profitable: profitable,
            pnlBps:     pnlBps,
            confidence: confidence,
            timestamp:  block.timestamp
        }));

        uint256 newScore = agentRegistry.getTrustScore(agentId);
        emit ReputationUpdated(
            agentId, newScore, delta,
            profitable
                ? "Profitable trade - trust increased"
                : "Unprofitable trade - trust decreased"
        );
    }

    // ── Score delta logic ─────────────────────────────────────────────────────

    function _computeDelta(
        bool profitable,
        int256 pnlBps,
        uint256 confidence
    ) internal pure returns (int256 delta) {
        if (profitable) {
            if      (confidence >= 75) delta = 5;
            else if (confidence >= 55) delta = 3;
            else                       delta = 1;
            if (pnlBps > 200) delta += 1; // >2% bonus
        } else {
            if      (confidence >= 75) delta = -3;
            else if (confidence >= 55) delta = -2;
            else                       delta = -1;
        }
        if (delta > MAX_POSITIVE_DELTA) delta = MAX_POSITIVE_DELTA;
        if (delta < MAX_NEGATIVE_DELTA) delta = MAX_NEGATIVE_DELTA;
    }

    // ── Drawdown + Sharpe proxy tracking ──────────────────────────────────────

    /**
     * @notice Update per-agent drawdown and running Sharpe-proxy stats.
     *
     * Drawdown:
     *   currentPnl   += pnlBps
     *   peakPnl       = max(peakPnl, currentPnl)
     *   drawdown      = peakPnl - currentPnl
     *   maxDrawdown   = max(maxDrawdown, drawdown)
     *
     * Sharpe proxy inputs (use off-chain to compute final ratio):
     *   avg   = sumPnlBps / tradeCount
     *   stdDev = sqrt(sumSquaredPnlBps/n - avg²)
     *   Sharpe ≈ avg / stdDev
     */
    function _updateAgentStats(
        uint256 agentId,
        bool    profitable,
        int256  pnlBps
    ) internal {
        AgentStats storage s = agentStats[agentId];

        s.currentPnlBps += pnlBps;
        s.sumPnlBps     += pnlBps;
        s.tradeCount    += 1;
        s.lastUpdated    = block.timestamp;

        if (profitable) s.winCount  += 1;
        else            s.lossCount += 1;

        int256 absPnl = pnlBps < 0 ? -pnlBps : pnlBps;
        s.sumSquaredPnlBps += uint256(absPnl * absPnl);

        if (s.currentPnlBps > s.peakPnlBps) {
            s.peakPnlBps = s.currentPnlBps;
        }

        int256 drawdown = s.peakPnlBps - s.currentPnlBps;
        if (drawdown > 0) {
            uint256 drawdownAbs = uint256(drawdown);
            if (drawdownAbs > s.maxDrawdownBps) {
                s.maxDrawdownBps = drawdownAbs;
                emit DrawdownUpdated(agentId, drawdownAbs);
            }
        }
    }

    // ── View ──────────────────────────────────────────────────────────────────

    function getAgentHistory(uint256 agentId)
        external view returns (ScoreUpdate[] memory)
    {
        return agentHistory[agentId];
    }

    function getTrustScore(uint256 agentId) external view returns (uint256) {
        return agentRegistry.getTrustScore(agentId);
    }

    /**
     * @notice Get all performance stats for leaderboard display.
     * @return peakPnlBps       Highest cumulative PnL ever reached.
     * @return currentPnlBps    Current cumulative PnL.
     * @return maxDrawdownBps   Maximum peak-to-trough drawdown (abs bps).
     * @return avgPnlBps        Average per-trade PnL in basis points.
     * @return winRate          Win rate × 10000 (e.g. 6750 = 67.50%).
     * @return tradeCount       Total number of settled trades.
     * @return sumSquaredPnlBps Sum of squared per-trade PnLs (for off-chain stdDev).
     */
    function getAgentPerformance(uint256 agentId)
        external view
        returns (
            int256  peakPnlBps,
            int256  currentPnlBps,
            uint256 maxDrawdownBps,
            int256  avgPnlBps,
            uint256 winRate,
            uint256 tradeCount,
            uint256 sumSquaredPnlBps
        )
    {
        AgentStats storage s = agentStats[agentId];
        tradeCount       = s.tradeCount;
        peakPnlBps       = s.peakPnlBps;
        currentPnlBps    = s.currentPnlBps;
        maxDrawdownBps   = s.maxDrawdownBps;
        sumSquaredPnlBps = s.sumSquaredPnlBps;
        avgPnlBps        = tradeCount > 0 ? s.sumPnlBps / int256(tradeCount) : int256(0);
        winRate          = tradeCount > 0 ? (s.winCount * 10000) / tradeCount : 0;
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    /**
     * @notice Grant or revoke authorization.
     *         After deployment wire in RiskRouter:
     *           reputationManager.setAuthorizedCaller(riskRouterAddress, true)
     */
    function setAuthorizedCaller(address caller, bool authorized) external onlyOwner {
        authorizedCallers[caller] = authorized;
        emit AuthorizedCallerSet(caller, authorized);
    }
}

contracts/RiskRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./AgentRegistry.sol";
import "./Interfaces.sol";

/**
 * @title RiskRouter
 * @notice On-chain risk gatekeeper for AI trading agents.
 *
 *         Before any trade executes, the RiskRouter:
 *         1. Verifies the EIP-712 signature — ECDSA first, EIP-1271 fallback
 *            for contract wallets (Safe, AA wallets)
 *         2. Compares signer to the agent owner recorded in AgentRegistry
 *         3. Checks trade limits (single trade + daily loss)
 *         4. Verifies the token is in the allowed list
 *         5. Emits TradeApproved / TradeRejected for indexers
 *         6. Optionally calls the DEX router for on-chain execution
 */
contract RiskRouter {

    // ── Events ────────────────────────────────────────────────────────────────
    event TradeApproved(
        uint256 indexed agentId,
        address indexed wallet,
        bytes32 tradeHash,
        string  tokenPair,
        string  action,
        uint256 amountUsd
    );
    event TradeRejected(
        uint256 indexed agentId,
        bytes32 tradeHash,
        string  reason
    );
    event TradeExecuted(
        uint256 indexed agentId,
        bytes32 tradeHash,
        uint256[] amounts
    );
    event TokenAllowlistUpdated(string token, bool allowed);
    event LimitsUpdated(uint256 maxSingleTradeUsd, uint256 maxDailyLossUsd);
    event DEXRouterUpdated(address dexRouter);

    // ── Structs ───────────────────────────────────────────────────────────────
    struct TradeIntent {
        uint256 agentId;
        string  tokenPair;    // e.g. "ETH/USDC"
        string  action;       // "BUY" | "SELL"
        uint256 amountUsd;    // in USD cents (e.g. 10000 = $100)
        uint256 confidence;   // 0-100
        string  reason;
        uint256 nonce;
        uint256 deadline;
        // DEX execution params (optional; zero = off-chain execution)
        address tokenIn;
        address tokenOut;
        uint256 amountIn;
        uint256 amountOutMin;
    }

    struct DailyStats {
        uint256 date;
        uint256 totalLossUsd;
        uint256 tradeCount;
    }

    // ── State ─────────────────────────────────────────────────────────────────
    AgentRegistry public agentRegistry;
    IDEXRouter    public dexRouter;
    address public owner;

    uint256 public maxSingleTradeUsd = 5_000 * 100;   // $5,000 in cents
    uint256 public maxDailyLossUsd   = 10_000 * 100;  // $10,000 in cents
    uint256 public minConfidence      = 45;

    bytes4 internal constant ERC1271_MAGIC_VALUE = 0x1626ba7e;

    mapping(string  => bool)       public allowedTokens;
    mapping(uint256 => DailyStats) public agentDailyStats;
    mapping(bytes32 => bool)       public processedTrades;
    mapping(uint256 => uint256)    public agentNonces;

    bytes32 public immutable DOMAIN_SEPARATOR;
    bytes32 public constant TRADE_TYPEHASH = keccak256(
        "TradeIntent(uint256 agentId,string tokenPair,string action,uint256 amountUsd,"
        "uint256 confidence,string reason,uint256 nonce,uint256 deadline,"
        "address tokenIn,address tokenOut,uint256 amountIn,uint256 amountOutMin)"
    );

    modifier onlyOwner() {
        require(msg.sender == owner, "RiskRouter: not owner");
        _;
    }

    constructor(address _agentRegistry) {
        owner         = msg.sender;
        agentRegistry = AgentRegistry(_agentRegistry);

        allowedTokens["ETH"]   = true;
        allowedTokens["BTC"]   = true;
        allowedTokens["MATIC"] = true;
        allowedTokens["LINK"]  = true;
        allowedTokens["UNI"]   = true;
        allowedTokens["AAVE"]  = true;
        allowedTokens["USDC"]  = true;
        allowedTokens["WETH"]  = true;

        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"),
                keccak256(bytes("AITradingAgent")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    // ── Core ──────────────────────────────────────────────────────────────────

    /**
     * @notice Submit a signed trade intent for risk validation.
     * @param intent    The trade parameters.
     * @param signature Raw EIP-712 signature (65-byte ECDSA or EIP-1271 bytes).
     * @return approved  Whether the trade passed all risk checks.
     * @return tradeHash Unique hash for this trade.
     */
    function submitTrade(
        TradeIntent calldata intent,
        bytes calldata signature
    ) external returns (bool approved, bytes32 tradeHash) {
        require(block.timestamp <= intent.deadline, "RiskRouter: trade expired");
        require(
            intent.nonce == agentNonces[intent.agentId],
            "RiskRouter: invalid nonce"
        );

        tradeHash = _hashTrade(intent);
        require(!processedTrades[tradeHash], "RiskRouter: already processed");

        // ── Signer MUST be the agent owner (ECDSA + EIP-1271 fallback) ────────
        address agentOwner = _getAgentOwner(intent.agentId);
        require(
            _isValidSignature(agentOwner, tradeHash, signature),
            "RiskRouter: signer is not agent owner"
        );

        (bool passed, string memory rejectReason) = _runRiskChecks(intent);

        processedTrades[tradeHash] = true;
        agentNonces[intent.agentId]++;

        if (passed) {
            _updateDailyStats(intent);
            emit TradeApproved(
                intent.agentId,
                agentOwner,
                tradeHash,
                intent.tokenPair,
                intent.action,
                intent.amountUsd
            );

            // Optional on-chain DEX execution
            if (
                address(dexRouter) != address(0) &&
                intent.tokenIn  != address(0)    &&
                intent.tokenOut != address(0)    &&
                intent.amountIn > 0
            ) {
                _executeDEXSwap(intent, tradeHash, agentOwner);
            }

            return (true, tradeHash);
        } else {
            emit TradeRejected(intent.agentId, tradeHash, rejectReason);
            return (false, tradeHash);
        }
    }

    // ── Internal helpers ──────────────────────────────────────────────────────

    /**
     * @notice Validate signature — ECDSA first, then EIP-1271 for contract wallets.
     */
    function _isValidSignature(
        address signer,
        bytes32 hash,
        bytes memory signature
    ) internal view returns (bool) {
        // 1. ECDSA (EOA wallets)
        if (signature.length == 65) {
            bytes32 r; bytes32 s; uint8 v;
            assembly {
                r := mload(add(signature, 32))
                s := mload(add(signature, 64))
                v := byte(0, mload(add(signature, 96)))
            }
            address recovered = ecrecover(hash, v, r, s);
            if (recovered != address(0) && recovered == signer) return true;
        }

        // 2. EIP-1271 fallback (Safe, AA, Multisig)
        if (signer.code.length > 0) {
            try IERC1271(signer).isValidSignature(hash, signature)
                returns (bytes4 result)
            {
                return result == ERC1271_MAGIC_VALUE;
            } catch {
                return false;
            }
        }
        return false;
    }

    function _getAgentOwner(uint256 agentId)
        internal view returns (address agentOwner)
    {
        (,, agentOwner,,,,) = agentRegistry.getAgent(agentId);
        require(agentOwner != address(0), "RiskRouter: agent not found");
    }

    function _runRiskChecks(TradeIntent calldata intent)
        internal view returns (bool, string memory)
    {
        if (intent.confidence < minConfidence)
            return (false, "Confidence below minimum");

        if (intent.amountUsd > maxSingleTradeUsd)
            return (false, "Exceeds single trade limit");

        string memory baseToken = _extractBaseToken(intent.tokenPair);
        if (!allowedTokens[baseToken])
            return (false, "Token not in allowlist");

        DailyStats storage stats = agentDailyStats[intent.agentId];
        uint256 today = block.timestamp / 86400;
        if (stats.date == today && stats.totalLossUsd >= maxDailyLossUsd)
            return (false, "Daily loss limit reached");

        (,,,, bool active,,) = agentRegistry.getAgent(intent.agentId);
        if (!active)
            return (false, "Agent not active");

        return (true, "");
    }

    function _executeDEXSwap(
        TradeIntent calldata intent,
        bytes32 tradeHash,
        address recipient
    ) internal {
        address[] memory path = new address[](2);
        path[0] = intent.tokenIn;
        path[1] = intent.tokenOut;

        uint256[] memory amounts = dexRouter.swapExactTokensForTokens(
            intent.amountIn,
            intent.amountOutMin,
            path,
            recipient,
            intent.deadline
        );

        emit TradeExecuted(intent.agentId, tradeHash, amounts);
    }

    function _updateDailyStats(TradeIntent calldata intent) internal {
        uint256 today = block.timestamp / 86400;
        DailyStats storage stats = agentDailyStats[intent.agentId];
        if (stats.date != today) {
            stats.date         = today;
            stats.totalLossUsd = 0;
            stats.tradeCount   = 0;
        }
        stats.tradeCount++;
    }

    function _hashTrade(TradeIntent calldata intent)
        internal view returns (bytes32)
    {
        bytes32 structHash = keccak256(
            abi.encode(
                TRADE_TYPEHASH,
                intent.agentId,
                keccak256(bytes(intent.tokenPair)),
                keccak256(bytes(intent.action)),
                intent.amountUsd,
                intent.confidence,
                keccak256(bytes(intent.reason)),
                intent.nonce,
                intent.deadline,
                intent.tokenIn,
                intent.tokenOut,
                intent.amountIn,
                intent.amountOutMin
            )
        );
        return keccak256(abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash));
    }

    function _extractBaseToken(string calldata pair)
        internal pure returns (string memory)
    {
        bytes memory b = bytes(pair);
        uint256 slashIdx = 0;
        for (uint256 i = 0; i < b.length; i++) {
            if (b[i] == "/") { slashIdx = i; break; }
        }
        if (slashIdx == 0) return pair;
        bytes memory base = new bytes(slashIdx);
        for (uint256 i = 0; i < slashIdx; i++) base[i] = b[i];
        return string(base);
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setLimits(uint256 maxSingle, uint256 maxDaily) external onlyOwner {
        maxSingleTradeUsd = maxSingle;
        maxDailyLossUsd   = maxDaily;
        emit LimitsUpdated(maxSingle, maxDaily);
    }

    function setTokenAllowed(string calldata token, bool allowed) external onlyOwner {
        allowedTokens[token] = allowed;
        emit TokenAllowlistUpdated(token, allowed);
    }

    function setMinConfidence(uint256 threshold) external onlyOwner {
        minConfidence = threshold;
    }

    function setDEXRouter(address router) external onlyOwner {
        dexRouter = IDEXRouter(router);
        emit DEXRouterUpdated(router);
    }

    // ── View ──────────────────────────────────────────────────────────────────

    function getAgentNonce(uint256 agentId) external view returns (uint256) {
        return agentNonces[agentId];
    }

    function isTradeProcessed(bytes32 tradeHash) external view returns (bool) {
        return processedTrades[tradeHash];
    }
}

